module top_module (
    input [3:0] d,
    output reg [1:0] y,
    output reg invalid
);

    always @(*) begin
        invalid = 1;
        casex (d)
            4'b1xxx: y = 2'b11;
            4'b01xx: y = 2'b10;
            4'b001x: y = 2'b01;
            4'b0001: y = 2'b00;
            default: begin
                y = 2'b00;
                invalid = 0;
            end
        endcase
    end

endmodule
